SELECT ROUND(SUM(tiv_2016)::NUMERIC , 2) AS tiv_2016 FROM (SELECT tiv_2015 , SUM(tiv_2016) AS tiv_2016 FROM (SELECT * FROM Insurance WHERE lat::VARCHAR || lon::VARCHAR IN (SELECT lat::VARCHAR || lon::VARCHAR FROM Insurance GROUP BY lat, lon HAVING COUNT(*) = 1))
WHERE tiv_2015 IN (SELECT tiv_2015 FROM Insurance GROUP BY tiv_2015 HAVING COUNT(tiv_2015) > 1)
GROUP BY tiv_2015);